import * as React from "react";
import { Link, type PageProps } from "gatsby";
import { useAllPosts } from "./_query";
import { Card, CardContent, CardTitle } from "@/components/ui/card";

const IndexPage: React.FC<PageProps> = () => {
  const allPosts = useAllPosts();
  const totalWordCount = allPosts.reduce(
    (prev, curr) => prev + curr.node.fields.timeToRead.words,
    0,
  );
  return (
    <div>
      <h1>Welcome!</h1>
      <p>
        Here lies my attempt at creating and maintaining a digital record of my
        organized (or not) thoughts. I have this site currently broken up into
        two specific namespaces:
      </p>
      <ol>
        <li>
          <Link to="/blog/tech">Tech</Link> - things related to tech
        </li>
        <li>
          <Link to="/blog/space">Space</Link> - a wide open space for everything
          else
        </li>
        <li>Various tools (coming eventually)</li>
        <li>Project showcase (if I ever finish any)</li>
      </ol>
      <h3>Goals</h3>
      <p>
        As with any project, my first goal is to get this site up and hosted, so
        if you're seeing this, then success! Many of my projects don't see the
        light of day. In order to be realistic, my main goal for this site is to
        just be a place of written exploration more than anything. Maybe I can
        help some others with my tech posts and maybe I can inspire others with
        my non-tech posts.
      </p>
      <p>
        For an idea of some of the things I might write about, see my{" "}
        <Link to="/about">about page</Link>.
      </p>
      <h3>Stats</h3>
      <p>Just for fun:</p>
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 my-4">
        <Card className="p-4">
          <CardTitle>Total words written for posts</CardTitle>
          <CardContent>{totalWordCount}</CardContent>
        </Card>
      </div>
    </div>
  );
};

export default IndexPage;
