import { graphql, useStaticQuery } from "gatsby";
import type { Post } from "@/lib/types/post";

const useAllPosts = () => {
  const data = useStaticQuery(graphql`
    query AllPosts {
      all: allMdx(
        filter: { internal: { contentFilePath: { regex: "/posts/" } } }
      ) {
        edges {
          node {
            fields {
              timeToRead {
                minutes
                text
                time
                words
              }
            }
            frontmatter {
              title
              description
              date
            }
            internal {
              contentFilePath
            }
          }
        }
      }
    }
  `);
  return data.all.edges as Post[];
};

export { useAllPosts };
